function seedId(fontName: string, lanzouUrl: string): string {
  let hash = 2166136261;
  const value = `${fontName}|${lanzouUrl}`;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return `seed-${(hash >>> 0).toString(36)}`;
}

export function createFontSeedItems(): FontLinkItem[] {
  return FONT_SEED_PAIRS.map(([fontName, lanzouUrl]) => ({
    id: seedId(fontName, lanzouUrl),
    fontName,
    lanzouUrl,
    sourceLine: `${fontName} ${lanzouUrl}`,
  }));
}

export const FONT_SEED_COUNT = FONT_SEED_PAIRS.length;
